"use client";

import { useEffect, useState } from "react";
import { apiRequest } from "@/lib/api";
import { useAuth } from "@/context/AuthContext";
import toast from "react-hot-toast";

export default function ProfilePage() {
  const { token, logout } = useAuth();

  const [form, setForm] = useState({
    name: "",
    email: "",
    phoneNumber: "",
    address: "",
  });

  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    if (!token) return;

    apiRequest("/users/me", "GET", undefined, token)
      .then((data) => {
        setForm({
          name: data.name,
          email: data.email,
          phoneNumber: data.phone_number || "",
          address: data.address || "",
        });
      })
      .finally(() => setLoading(false));
  }, [token]);

  if (!token) {
    return (
      <main className="px-6 py-32 text-center opacity-70">
        Please login to view your profile.
      </main>
    );
  }

  if (loading) {
    return (
      <main className="px-6 py-32 text-center opacity-70">
        Loading profile…
      </main>
    );
  }

  const handleSave = async () => {
    try {
      setSaving(true);

      await apiRequest(
        "/users/me",
        "PUT",
        {
          name: form.name,
          phoneNumber: form.phoneNumber,
          address: form.address,
        },
        token
      );

      toast.success("Profile updated successfully");
    } catch (err: any) {
      toast.error(err.message);
    } finally {
      setSaving(false);
    }
  };

  return (
    <main className="px-6 py-32 max-w-3xl mx-auto">
      <h1 className="font-[var(--font-serif)] text-5xl mb-12">
        Profile
      </h1>

      {/* FORM CARD */}
      <div className="
        bg-[var(--color-blush)]
        border border-[var(--color-rose)]
        rounded-xl
        p-8
        space-y-6
      ">
        {/* NAME */}
        <div>
          <label className="block text-sm mb-2 opacity-80">
            Name
          </label>
          <input
            className="
              w-full p-3
              border border-[var(--color-rose)]
              bg-white/60
              rounded
              focus:outline-none
              focus:border-[var(--color-accent)]
            "
            value={form.name}
            onChange={(e) =>
              setForm({ ...form, name: e.target.value })
            }
          />
        </div>

        {/* EMAIL */}
        <div>
          <label className="block text-sm mb-2 opacity-80">
            Email
          </label>
          <input
            className="
              w-full p-3
              border border-[var(--color-rose)]
              bg-black/5
              rounded
              opacity-70
            "
            value={form.email}
            disabled
          />
        </div>

        {/* PHONE */}
        <div>
          <label className="block text-sm mb-2 opacity-80">
            Phone number
          </label>
          <input
            className="
              w-full p-3
              border border-[var(--color-rose)]
              bg-white/60
              rounded
              focus:outline-none
              focus:border-[var(--color-accent)]
            "
            value={form.phoneNumber}
            onChange={(e) =>
              setForm({ ...form, phoneNumber: e.target.value })
            }
          />
        </div>

        {/* ADDRESS */}
        <div>
          <label className="block text-sm mb-2 opacity-80">
            Address
          </label>
          <textarea
            rows={3}
            className="
              w-full p-3
              border border-[var(--color-rose)]
              bg-white/60
              rounded
              focus:outline-none
              focus:border-[var(--color-accent)]
            "
            value={form.address}
            onChange={(e) =>
              setForm({ ...form, address: e.target.value })
            }
          />
        </div>
      </div>

      {/* ACTIONS */}
      <div className="flex items-center gap-8 mt-10">
        <button
          onClick={handleSave}
          disabled={saving}
          className="
            bg-[var(--color-accent)]
            text-white
            px-10 py-3
            uppercase tracking-widest text-sm
            hover:opacity-90
            transition
            disabled:opacity-50
          "
        >
          {saving ? "Saving…" : "Save Changes"}
        </button>

        <button
          onClick={logout}
          className="text-sm opacity-70 hover:underline"
        >
          Logout
        </button>
      </div>
    </main>
  );
}